import { Column, Heading, Text, Button, Avatar } from "@once-ui-system/core";
import { home, baseURL } from "@/resources";
import { Projects } from "@/components/work/Projects";

export async function generateMetadata() {
  return {
    title: home.title,
    description: home.description,
    metadataBase: new URL(baseURL),
    openGraph: {
      title: home.title,
      description: home.description,
      url: `${baseURL}${home.path}`,
      images: [
        `${baseURL}/api/og/generate?title=${encodeURIComponent(home.title)}`,
      ],
    },
  };
}

export default function Home() {
  return (
    <Column fill as="main" center gap="xl" paddingY="12">
      <Column fillWidth maxWidth="m" horizontal="center" gap="m" style={{ textAlign: "center" }}>
        <Avatar size="xl" src="" />
        {home.featured.display && (
          <Button
            href={home.featured.href}
            variant="secondary"
            size="s"
          >
            {home.featured.title}
          </Button>
        )}
        <Heading as="h1" variant="display-strong-xl">
          #wearewidely
        </Heading>
        <Text as="p" variant="body-default-xl" onBackground="neutral-weak">
          A post-production house is where ideas turns into a finished story through editing, sound, color, and creative finishing touches.
        </Text>
      </Column>

      <Column fillWidth maxWidth="l" horizontal="center" paddingTop="xl">
        <Projects range={[1, 2]} />
      </Column>
    </Column>
  );
}
